import java.lang.Math;

public static boolean solve(long n) {
    long sum = 0;
    long product = 1;
    long num = n;

    while (num > 0) {
        long digit = num % 10;
        sum += digit;
        product *= digit;
        num /= 10;
    }

    long total = sum + product;
    return total % n == 0;
}
